import { useState, useRef, useEffect } from 'react'
import { useParams } from 'react-router-dom'
import printProducts from '../data/printProducts'

export default function ProductCustomizer() {

  const { id } = useParams()

  const product = printProducts.find(
    item => item.id === id
  )

  const containerRef = useRef(null)

  const [selectedColor, setSelectedColor] = useState(
    product.colors[0]
  )

  const [selectedSize, setSelectedSize] = useState('M')

  const [uploadedLogo, setUploadedLogo] = useState(null)

  const [uploadedFile, setUploadedFile] = useState(null)

  const [logoSize, setLogoSize] = useState(220)

  const [isDragging, setIsDragging] = useState(false)

  const [activePreset, setActivePreset] = useState('front')

  const [logoPosition, setLogoPosition] = useState({
    x: 50,
    y: 42
  })

  const [customerName, setCustomerName] = useState('')

  const [customerEmail, setCustomerEmail] = useState('')

  const [customerPhone, setCustomerPhone] = useState('')

  const [quantity, setQuantity] = useState('24')

  const [notes, setNotes] = useState('')

  const [showSuccess, setShowSuccess] = useState(false)

  const [showSummary, setShowSummary] = useState(false)

  useEffect(() => {

    const savedQuote =
      localStorage.getItem('latestQuote')

    if (savedQuote) {

      const parsed =
        JSON.parse(savedQuote)

      setCustomerName(parsed.customerName || '')
      setCustomerEmail(parsed.customerEmail || '')
      setCustomerPhone(parsed.customerPhone || '')
      setNotes(parsed.notes || '')
      setQuantity(parsed.quantity || '24')
    }

  }, [])

  const handleUpload = (e) => {

    const file = e.target.files[0]

    if (file) {

      setUploadedFile(file)

      setUploadedLogo(
        URL.createObjectURL(file)
      )
    }
  }

  const handleMouseMove = (e) => {

    if (!isDragging) return

    const rect =
      containerRef.current.getBoundingClientRect()

    const x =
      ((e.clientX - rect.left) / rect.width) * 100

    const y =
      ((e.clientY - rect.top) / rect.height) * 100

    setLogoPosition({
      x,
      y
    })
  }

  const handleMouseUp = () => {
    setIsDragging(false)
  }

  const setPreset = (type) => {

    setActivePreset(type)

    if (type === 'front') {
      setLogoPosition({ x: 50, y: 42 })
      setLogoSize(220)
    }

    if (type === 'left-chest') {
      setLogoPosition({ x: 38, y: 32 })
      setLogoSize(120)
    }

    if (type === 'oversized') {
      setLogoPosition({ x: 50, y: 45 })
      setLogoSize(420)
    }

    if (type === 'back') {
      setLogoPosition({ x: 50, y: 42 })
      setLogoSize(320)
    }

    if (type === 'sleeve') {
      setLogoPosition({ x: 72, y: 33 })
      setLogoSize(90)
    }
  }

  const submitQuote = () => {

    if (
      !customerName ||
      !customerEmail ||
      !customerPhone
    ) {

      alert('Please complete required fields')

      return
    }

    const quoteData = {

      product: product.name,

      color: selectedColor.name,

      size: selectedSize,

      quantity,

      placement: activePreset,

      customerName,

      customerEmail,

      customerPhone,

      notes,

      uploadedFile: uploadedFile
        ? uploadedFile.name
        : 'No File'
    }

    console.log(quoteData)

    localStorage.setItem(
      'latestQuote',
      JSON.stringify(quoteData)
    )

    setShowSuccess(true)

    setShowSummary(true)

    setTimeout(() => {

      setShowSuccess(false)

    }, 4000)
  }

  return (

    <div
      className="min-h-screen bg-black text-white px-4 py-6 overflow-hidden"
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
    >

      {showSuccess && (

        <div className="fixed top-5 right-5 z-50 bg-yellow-500 text-black px-6 py-4 rounded-2xl font-black text-sm shadow-2xl">

          Quote Request Submitted

        </div>

      )}

      <div className="max-w-[1800px] mx-auto grid grid-cols-1 xl:grid-cols-2 gap-8 items-start">


        <div
          ref={containerRef}
          className="bg-[#111] border border-[#222] rounded-[30px] p-4 flex items-center justify-center relative overflow-hidden min-h-[720px]"
        >

          <img
            src={
              activePreset === 'back'
                ? selectedColor.backImage
                : selectedColor.image
            }
            alt="product"
            className="w-full max-w-[600px] relative z-10"
          />

          {uploadedLogo && (

            <img
              src={uploadedLogo}
              alt="logo"
              onMouseDown={() => setIsDragging(true)}
              className="absolute z-20 opacity-95 select-none"
              style={{
                width: `${logoSize}px`,
                top: `${logoPosition.y}%`,
                left: `${logoPosition.x}%`,
                transform: 'translate(-50%, -50%)',
                cursor: isDragging ? 'grabbing' : 'grab'
              }}
              draggable={false}
            />

          )}

        </div>


        <div className="max-h-[95vh] overflow-y-auto pr-2">

          <p className="text-yellow-500 tracking-[0.3em] uppercase text-[10px] mb-3">
            Inspired By God Print Division
          </p>

          <h1 className="text-5xl font-black leading-none mb-3">
            {product.name}
          </h1>

          <p className="text-2xl text-yellow-500 mb-8">
            Starting at ${product.price}
          </p>


          <div className="space-y-8">


            <div>

              <h2 className="text-lg font-bold mb-4">
                Quick Placement
              </h2>

              <div className="flex flex-wrap gap-3">

                {[
                  'front',
                  'left-chest',
                  'oversized',
                  'back',
                  'sleeve'
                ].map((item) => (

                  <button
                    key={item}
                    onClick={() => setPreset(item)}
                    className={`px-4 py-3 rounded-xl text-sm font-black transition ${
                      activePreset === item
                        ? 'bg-yellow-500 text-black'
                        : 'border border-[#333] text-white'
                    }`}
                  >
                    {item}
                  </button>

                ))}

              </div>

            </div>


            <div>

              <h2 className="text-lg font-bold mb-4">
                Colors
              </h2>

              <div className="flex gap-3 flex-wrap">

                {product.colors.map((color) => (

                  <button
                    key={color.name}
                    onClick={() => setSelectedColor(color)}
                    className={`w-12 h-12 rounded-full border-4 ${
                      selectedColor.name === color.name
                        ? 'border-yellow-500'
                        : 'border-white'
                    }`}
                    style={{
                      backgroundColor: color.hex
                    }}
                  />

                ))}

              </div>

            </div>


            <div>

              <h2 className="text-lg font-bold mb-4">
                Sizes
              </h2>

              <div className="flex flex-wrap gap-3">

                {['S','M','L','XL','2XL','3XL'].map((size) => (

                  <button
                    key={size}
                    onClick={() => setSelectedSize(size)}
                    className={`px-5 py-3 rounded-xl text-sm font-bold ${
                      selectedSize === size
                        ? 'bg-yellow-500 text-black'
                        : 'border border-[#333]'
                    }`}
                  >
                    {size}
                  </button>

                ))}

              </div>

            </div>


            <div>

              <h2 className="text-lg font-bold mb-4">
                Quantity
              </h2>

              <input
                type="number"
                value={quantity}
                onChange={(e) =>
                  setQuantity(e.target.value)
                }
                className="w-full bg-[#111] border border-[#222] rounded-xl p-4 text-white"
              />

            </div>


            <div>

              <h2 className="text-lg font-bold mb-4">
                Upload Logo
              </h2>

              <input
                type="file"
                accept="image/png,image/jpeg"
                onChange={handleUpload}
                className="w-full bg-[#111] border border-[#222] rounded-xl p-4"
              />

            </div>


            <div>

              <h2 className="text-lg font-bold mb-4">
                Resize Logo
              </h2>

              <input
                type="range"
                min="80"
                max="500"
                value={logoSize}
                onChange={(e) =>
                  setLogoSize(e.target.value)
                }
                className="w-full"
              />

            </div>


            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">

              <input
                type="text"
                placeholder="Your Name"
                value={customerName}
                onChange={(e) =>
                  setCustomerName(e.target.value)
                }
                className="bg-[#111] border border-[#222] rounded-xl p-4 text-white"
              />

              <input
                type="email"
                placeholder="Email Address"
                value={customerEmail}
                onChange={(e) =>
                  setCustomerEmail(e.target.value)
                }
                className="bg-[#111] border border-[#222] rounded-xl p-4 text-white"
              />

            </div>


            <div>

              <input
                type="text"
                placeholder="Phone Number"
                value={customerPhone}
                onChange={(e) =>
                  setCustomerPhone(e.target.value)
                }
                className="w-full bg-[#111] border border-[#222] rounded-xl p-4 text-white"
              />

            </div>


            <div>

              <textarea
                rows="4"
                placeholder="Additional Notes"
                value={notes}
                onChange={(e) =>
                  setNotes(e.target.value)
                }
                className="w-full bg-[#111] border border-[#222] rounded-xl p-4 text-white"
              />

            </div>


            <button
              onClick={submitQuote}
              className="w-full bg-yellow-500 text-black py-5 rounded-2xl text-lg font-black"
            >

              REQUEST QUOTE

            </button>


            {showSummary && (

              <div className="bg-[#111] border border-[#222] rounded-[24px] p-6">

                <h2 className="text-2xl font-black mb-5">
                  Quote Summary
                </h2>

                <div className="space-y-3 text-sm">

                  <p>
                    Product: {product.name}
                  </p>

                  <p>
                    Color: {selectedColor.name}
                  </p>

                  <p>
                    Size: {selectedSize}
                  </p>

                  <p>
                    Quantity: {quantity}
                  </p>

                  <p>
                    Placement: {activePreset}
                  </p>

                  <p>
                    File: {
                      uploadedFile
                        ? uploadedFile.name
                        : 'No File'
                    }
                  </p>

                </div>

              </div>

            )}

          </div>

        </div>

      </div>

    </div>

  )
}
